INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-reading'), 'Reading Practice Test 1', 'OC (Grade 4) Reading - Practice Test Set 1', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (1, 1, 'The brave knight entered the dark cave. He could hear water dripping from the ceiling and the flutter of bat wings. Although he was afraid, he knew the dragon''s treasure lay deep within. He gripped his sword tightly and pressed forward into the darkness.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (1, 2, 'Sarah watched the caterpillar inch along the leaf. She noticed tiny hairs covering its body and the way it moved in waves, like the ocean. For weeks she returned to the same bush, watching the caterpillar grow and change until one day, it spun a silky cocoon around itself.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (1, 3, 'Ella placed her ingredients on the counter: flour, sugar, butter, and eggs. She measured each carefully, just as her grandmother had taught her. ''Baking is like science,'' her grandmother always said. ''Every ingredient has a purpose.'' Ella smiled, remembering the first time they had baked together when she was only five years old.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (1, 4, 'The Australian outback is home to many unique animals. Kangaroos bound across the red sand while emus sprint at incredible speeds. At night, the bilby emerges from its burrow to search for seeds and insects. These animals have adapted to survive in one of the world''s harshest environments.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (1, 5, 'Rain splattered against the classroom window as Ms Chen announced the results of the science fair. Jason had spent three months building his model volcano. His hands were sweaty as he listened to the names being called. Third place went to Mia''s crystal garden. Second place went to Amit''s solar system. Jason''s heart sank.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (1, 6, 'Tomatoes are actually a fruit, not a vegetable. They belong to the same family as potatoes and peppers. Botanically speaking, a fruit is the part of a plant that contains seeds. Since tomatoes contain seeds and develop from the flower of the tomato plant, they meet the scientific definition of a fruit.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (1, 7, 'Marcus kicked off his shoes and raced across the hot sand toward the water. The waves were perfect today — not too big, not too small. His older brother David was already in the water, riding a wave toward shore with a huge grin on his face. ''Come on, slow coach!'' David shouted.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (1, 8, 'Koalas sleep for up to 20 hours a day. This is because their diet consists mainly of eucalyptus leaves, which are low in nutrients and hard to digest. By sleeping so much, koalas conserve the energy they need to process their food. Baby koalas, called joeys, spend their first six months in their mothers pouch.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (1, 9, 'Lucy stared at the blank page. Her pencil hovered above the paper, but no words came. She looked around the classroom at her classmates, all writing furiously. The clock ticked loudly. Five minutes left. She took a deep breath, thought about her favourite memory with her dog, Max, and began to write.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (1, 10, 'The Sydney Harbour Bridge opened in 1932 after eight years of construction. It connects the Sydney central business district to the North Shore. The bridge is nicknamed ''the Coathanger'' because of its arch-based design. Over 200,000 cars cross the bridge every day.
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-reading'), 'Reading Practice Test 2', 'OC (Grade 4) Reading - Practice Test Set 2', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (2, 1, 'Penguins are birds that cannot fly. Instead, their wings have evolved into flippers that make them excellent swimmers. Emperor penguins can dive to depths of over 500 metres and hold their breath for up to 20 minutes. They live in large colonies on the Antarctic ice.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (2, 2, 'The first bicycles were invented in the early 1800s. They had no pedals — riders pushed themselves along with their feet on the ground. The modern bicycle with pedals and a chain was developed in the 1880s. Today, bicycles are used worldwide for transport, sport, and recreation.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (2, 3, 'Olivia could hear her mother singing in the kitchen. It was the same song she had sung every Saturday morning while making pancakes. The smell of batter sizzling filled the house. Olivia stretched in her bed, knowing that in a few minutes her mother would call her down for the best breakfast of the week.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (2, 4, 'Aboriginal Australians have the oldest continuous culture on Earth, dating back over 65,000 years. They have a deep spiritual connection to the land, which is expressed through Dreamtime stories. These stories explain how the land, animals, and people came to be.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (2, 5, 'The reef was alive with colour. Bright orange clownfish darted between the purple tips of sea anemones. A green sea turtle glided slowly overhead, casting a shadow that passed over a group of striped angelfish. In the distance, a reef shark patrolled the deeper water.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (2, 6, 'Volcanoes form when molten rock, called magma, rises from deep within the Earth. When the pressure becomes too great, the magma erupts through the surface as lava. Some volcanoes erupt explosively, while others have gentle flows of lava that spread slowly across the landscape.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (2, 7, 'Ben stood at the edge of the diving board, toes curled over the rough surface. Below, the water looked impossibly far away. His swimming coach called out encouragement. Ben thought about all the practice dives he had done. He knew he could do this. He bounced three times and leaped.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (2, 8, 'The Moon is Earth''s only natural satellite. It orbits our planet at a distance of about 384,400 kilometres. The same side of the Moon always faces Earth because the Moon takes the same amount of time to rotate once as it does to orbit Earth once.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (2, 9, 'Ethan carefully unwrapped the gift. His grandmother had sent it all the way from England. Inside the box was a small wooden horse, hand-carved and painted. It looked exactly like the horse he had admired in the market when she visited last summer. Tears welled in his eyes.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (2, 10, 'An ecosystem is a community of living things interacting with each other and their environment. In a forest ecosystem, trees provide shelter for birds, insects break down dead leaves into soil, and fungi help tree roots absorb water and nutrients.
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-reading'), 'Reading Practice Test 3', 'OC (Grade 4) Reading - Practice Test Set 3', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (3, 1, 'Coral reefs are often called the rainforests of the sea because they support such a rich variety of life. Although they cover less than 1% of the ocean floor, they are home to about 25% of all marine species. Reefs are built by tiny animals called coral polyps.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (3, 2, 'The lighthouse keeper climbed the spiral staircase every evening. For forty years, he had lit the lamp that warned ships away from the rocky shore. Tonight was his last night before retirement. As the beam swept across the dark water, he felt a mixture of sadness and pride.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (3, 3, 'Honeybees communicate through dance. When a bee finds a good source of nectar, it returns to the hive and performs a wiggle dance. The direction and duration of the dance tell other bees exactly where to find the flowers. This remarkable system allows the entire hive to work together.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (3, 4, 'The Great Barrier Reef stretches over 2,300 kilometres along Australia''s northeast coast. It is the world''s largest coral reef system and can be seen from space. The reef is home to over 1,500 species of fish, 400 types of coral, and many other marine creatures.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (3, 5, 'Amir was nervous about his first day at a new school. He didn''t know anyone and worried about fitting in. At lunch, a boy named Leo sat next to him and asked about the book Amir was reading. By the end of lunch, they had discovered they both loved the same author.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (3, 6, 'Diamonds are formed deep within the Earth under extreme heat and pressure. They are made of pure carbon, the same element found in pencil lead. The difference is how the carbon atoms are arranged. In diamonds, the atoms form a rigid crystal structure, making it the hardest natural material.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (3, 7, 'Maya pressed her nose against the pet shop window. A small grey kitten with white paws was batting at a toy mouse. Maya had been saving her pocket money for months. She counted the coins in her pocket and walked through the door. The bell above jingled.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (3, 8, 'The human heart beats about 100,000 times each day, pumping blood throughout the body. It has four chambers: two atria and two ventricles. The right side pumps blood to the lungs, while the left side pumps oxygen-rich blood to the rest of the body.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (3, 9, 'Sophie stared at the piano keys. Her teacher had assigned a difficult piece, and Sophie had been practising for weeks. The recital was tomorrow. Her fingers trembled slightly as she played the most challenging section — but this time, she made it through without a single mistake.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (3, 10, 'Camels are well adapted to desert life. Their humps store fat, not water, which can be converted to energy when food is scarce. Camels can also close their nostrils to keep out sand and have long eyelashes to protect their eyes during sandstorms.
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-reading'), 'Reading Practice Test 4', 'OC (Grade 4) Reading - Practice Test Set 4', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (4, 1, 'The invention of the printing press in the 1400s changed the world. Before this, books had to be copied by hand, which made them rare and expensive. The printing press allowed books to be produced quickly and cheaply, spreading knowledge to more people than ever before.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (4, 2, 'The baobab tree, found in Africa and Australia, can live for over 1,000 years. Its trunk can store up to 120,000 litres of water, helping it survive long droughts. The tree''s bark is fire-resistant, and its fruit is rich in vitamin C.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (4, 3, 'Maya stared at the maths problem on the board. Fractions had always confused her. But today, Mrs Thompson had explained them using pizza slices. Suddenly, it all made sense. Maya''s hand shot up when the teacher asked for a volunteer. She solved the problem perfectly.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (4, 4, 'Antarctica is the coldest continent on Earth, with temperatures reaching as low as minus 89 degrees Celsius. Despite the extreme cold, animals like penguins, seals, and various seabirds thrive there. No humans live in Antarctica permanently, though scientists stay at research stations.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (4, 5, 'Finn and his grandfather sat on the pier, their fishing lines dangling in the water. ''I caught my first fish here when I was your age,'' his grandfather said. Just then, Finn felt a tug on his line. Together, they pulled up a shimmering silver fish.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (4, 6, 'The human skeleton has 206 bones that provide structure and protection. The smallest bone is in the ear and is called the stapes, which is only about 3 millimetres long. The largest bone is the femur, or thigh bone, which is stronger than concrete.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (4, 7, 'Ruby had been training for the cross-country race all term. Now, with the finish line in sight, her legs burned and her lungs ached. She could hear footsteps behind her, getting closer. Ruby thought of all the early morning runs and pushed herself faster.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (4, 8, 'Lightning is a powerful electrical discharge that occurs during thunderstorms. A lightning bolt can heat the surrounding air to about 30,000 degrees Celsius, which is five times hotter than the surface of the Sun. This sudden heating causes the air to expand rapidly, creating thunder.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (4, 9, 'Ravi and his sister Priya explored the tide pools at the beach. In one pool, they spotted a bright orange starfish clinging to a rock. Tiny crabs scuttled between the pebbles. Ravi pointed excitedly at a small octopus that had changed colour to match the seaweed.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (4, 10, 'The Amazon rainforest produces about 20% of the world''s oxygen. It is home to an estimated 10% of all species on Earth. However, deforestation threatens this vital ecosystem, with large areas being cleared for farming and logging each year.
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-reading'), 'Reading Practice Test 5', 'OC (Grade 4) Reading - Practice Test Set 5', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (5, 1, 'The Sydney Opera House is one of the most recognisable buildings in the world. Designed by Danish architect Jorn Utzon, it took 14 years to build and was opened in 1973. The distinctive roof was inspired by the sails of ships in Sydney Harbour.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (5, 2, 'Chloe checked the weather forecast before her camping trip. Sunny skies were predicted for the entire weekend. But when she arrived at the campsite, dark clouds were gathering. ''Australian weather,'' her dad laughed. ''If you don''t like it, just wait five minutes.''
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (5, 3, 'Gravity is the force that pulls objects toward each other. The more mass an object has, the stronger its gravitational pull. This is why we stay on the ground instead of floating into space. The Moon''s gravity is about one-sixth of Earth''s, which is why astronauts can jump much higher there.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (5, 4, 'Jack was competing in his first chess tournament. He had won his first three matches and was now in the semi-finals. Across the board sat a boy twice his size. Jack took a deep breath, remembered his training, and moved his knight. Thirty minutes later, he shook hands with a smile — he had won.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (5, 5, 'Bees are essential for pollinating many of the foods we eat. About one-third of the food we consume depends on bee pollination. Without bees, foods like apples, almonds, and avocados would become very scarce and expensive.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (5, 6, 'Photographs capture moments in time. Before digital cameras, people used film cameras that required the film to be developed using chemicals in a darkroom. The first photograph ever taken was in 1826 by Joseph Nicephore Niepce, and it required an exposure time of eight hours.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (5, 7, 'Bella and her mother planted a vegetable garden in their backyard. They prepared the soil, planted seeds in neat rows, and watered them every evening. After weeks of waiting, tiny green shoots appeared. Bella was thrilled to see the first tomato turning red on the vine.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (5, 8, 'Sound travels through the air as invisible waves. It moves at about 343 metres per second, which is why we see lightning before we hear thunder. Sound travels even faster through water and fastest through solid materials like steel.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (5, 9, 'Zara and her family went whale watching off the coast. For an hour, they saw nothing but ocean. Then, without warning, a massive humpback whale breached the surface, its entire body rising out of the water before crashing back down with a tremendous splash.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (5, 10, 'The water cycle describes how water moves between the Earth''s surface and the atmosphere. Water evaporates from oceans and lakes, forms clouds through condensation, and returns to the ground as precipitation. This cycle has been repeating for billions of years.
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-math-reasoning'), 'Mathematical Reasoning Practice Test 1', 'OC (Grade 4) Mathematical Reasoning - Practice Test Set 1', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (6, 1, 'Sarah has 24 apples. She wants to share them equally among 6 friends. How many apples does each friend get?', '3', '4', '5', '6', 'B', '24 ÷ 6 = 4 apples per friend.', 1);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (6, 2, 'What is the value of 7 × 8?', '54', '56', '58', '63', 'B', '7 × 8 = 56. You can think of it as 7 groups of 8, or 8 groups of 7.', 2);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (6, 3, 'A rectangle has a length of 12 cm and a width of 5 cm. What is its perimeter?', '34 cm', '17 cm', '60 cm', '25 cm', 'A', 'Perimeter = 2 × (12 + 5) = 2 × 17 = 34 cm.', 3);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (6, 4, 'If a pizza is cut into 8 equal slices and Tom eats 3 slices, what fraction of the pizza has he eaten?', '3/8', '1/3', '3/5', '5/8', 'A', 'Tom ate 3 out of 8 total slices, so 3/8.', 4);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (6, 5, 'What is the next number in the pattern: 2, 6, 18, 54, ___?', '108', '72', '162', '81', 'C', 'Each number is multiplied by 3: 2×3=6, 6×3=18, 18×3=54, 54×3=162.', 5);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (6, 6, 'A bus has 45 seats. If 28 seats are occupied, how many empty seats are there?', '17', '18', '27', '16', 'A', '45 - 28 = 17 empty seats.', 6);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (6, 7, 'What is 3/4 of 60?', '40', '45', '45', '50', 'B', '3/4 of 60 = 60 ÷ 4 × 3 = 15 × 3 = 45.', 7);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (6, 8, 'If a movie starts at 2:15 PM and lasts for 1 hour and 45 minutes, what time does it end?', '3:45 PM', '3:50 PM', '4:00 PM', '3:30 PM', 'C', '2:15 + 1 hour = 3:15, then + 45 minutes = 4:00 PM.', 8);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (6, 9, 'Liam has $5. He buys a pack of cards for $2.75. How much change does he receive?', '$2.25', '$3.25', '$2.50', '$1.75', 'A', '$5.00 - $2.75 = $2.25.', 9);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (6, 10, 'A garden is in the shape of a square with sides of 9 metres. What is the area of the garden?', '36 m²', '81 m²', '45 m²', '18 m²', 'B', 'Area of square = side × side = 9 × 9 = 81 m².', 10);
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-math-reasoning'), 'Mathematical Reasoning Practice Test 2', 'OC (Grade 4) Mathematical Reasoning - Practice Test Set 2', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (7, 1, 'What is 1,256 + 789?', '2,035', '2,045', '2,145', '1,945', 'B', '1,256 + 789 = 2,045. Add column by column starting from the right.', 1);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (7, 2, 'Emma ran 350 metres on Monday, 275 metres on Tuesday, and 400 metres on Wednesday. How many metres did she run in total?', '975 m', '1,000 m', '1,025 m', '950 m', 'C', '350 + 275 + 400 = 1,025 metres.', 2);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (7, 3, 'Which of these numbers is divisible by both 2 and 5?', '12', '15', '20', '25', 'C', '20 is divisible by 2 (20÷2=10) and by 5 (20÷5=4).', 3);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (7, 4, 'A farmer has 156 eggs. He packs them into cartons of 12. How many full cartons can he fill?', '12', '13', '14', '11', 'B', '156 ÷ 12 = 13 cartons exactly.', 4);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (7, 5, 'What is the missing number: 4, 9, 16, 25, ___?', '30', '35', '36', '49', 'C', 'These are square numbers: 2²=4, 3²=9, 4²=16, 5²=25, so 6²=36.', 5);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (7, 6, 'A triangle has angles measuring 60° and 50°. What is the measure of the third angle?', '70°', '60°', '50°', '80°', 'A', 'Sum of angles in a triangle = 180°. So 180° - 60° - 50° = 70°.', 6);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (7, 7, 'What is 15% of 200?', '15', '25', '30', '35', 'C', '15% = 15/100, so 15/100 × 200 = 30.', 7);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (7, 8, 'If 4 notebooks cost $12, how much would 7 notebooks cost at the same price?', '$18', '$21', '$24', '$28', 'B', 'Cost per notebook = $12 ÷ 4 = $3. 7 notebooks = 7 × $3 = $21.', 8);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (7, 9, 'What is the difference between the product of 9 and 7 and the sum of 9 and 7?', '47', '50', '63', '16', 'A', 'Product: 9×7=63. Sum: 9+7=16. Difference: 63-16=47.', 9);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (7, 10, 'A jug can hold 2 litres of water. How many 250 mL cups can be filled from the jug?', '6', '8', '4', '10', 'B', '2 litres = 2,000 mL. 2,000 ÷ 250 = 8 cups.', 10);
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-math-reasoning'), 'Mathematical Reasoning Practice Test 3', 'OC (Grade 4) Mathematical Reasoning - Practice Test Set 3', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (8, 1, 'What is the value of the digit 3 in the number 53,782?', '3', '30', '3,000', '300', 'C', 'In 53,782, the 3 is in the thousands place, so its value is 3,000.', 1);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (8, 2, 'A train travels 85 km in one hour. At this speed, how far will it travel in 4 hours?', '320 km', '340 km', '350 km', '360 km', 'B', '85 × 4 = 340 km.', 2);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (8, 3, 'What is 3/5 + 1/5?', '4/10', '4/5', '2/5', '3/10', 'B', '3/5 + 1/5 = 4/5. When denominators are the same, add the numerators.', 3);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (8, 4, 'How many minutes are there in 3 hours and 25 minutes?', '185 min', '205 min', '225 min', '195 min', 'B', '3 hours = 180 minutes. 180 + 25 = 205 minutes.', 4);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (8, 5, 'A class collected 875 bottle caps. If they want to make stacks of 25 caps each, how many stacks can they make?', '30', '35', '45', '50', 'B', '875 ÷ 25 = 35 stacks.', 5);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (8, 6, 'What is the simplest form of the fraction 24/36?', '2/3', '3/4', '4/6', '6/9', 'A', '24/36 ÷ 12/12 = 2/3.', 6);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (8, 7, 'Mia bought 3 packets of stickers. Each packet has 24 stickers. She gave 17 stickers to her brother. How many stickers does she have left?', '55', '45', '65', '72', 'A', 'Total stickers = 3 × 24 = 72. 72 - 17 = 55 stickers left.', 7);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (8, 8, 'If you fold a piece of paper in half and then in half again, how many equal parts does the paper have?', '2', '3', '4', '8', 'C', 'First fold creates 2 parts, second fold doubles it to 4 equal parts.', 8);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (8, 9, 'A number multiplied by 6 gives 54. What is the number?', '8', '9', '7', '10', 'B', '54 ÷ 6 = 9. So the number is 9.', 9);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (8, 10, 'What is the perimeter of a regular pentagon with sides of 7 cm?', '28 cm', '42 cm', '35 cm', '49 cm', 'C', 'A pentagon has 5 sides. 5 × 7 = 35 cm.', 10);
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-math-reasoning'), 'Mathematical Reasoning Practice Test 4', 'OC (Grade 4) Mathematical Reasoning - Practice Test Set 4', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (9, 1, 'A bookshelf has 8 shelves. Each shelf can hold 25 books. How many books can the bookshelf hold in total?', '175', '200', '225', '250', 'B', '8 × 25 = 200 books.', 1);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (9, 2, 'What is the next number: 100, 85, 70, 55, ___?', '35', '40', '45', '50', 'B', 'The pattern decreases by 15 each time: 55 - 15 = 40.', 2);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (9, 3, 'If today is Thursday, what day will it be in 10 days?', 'Sunday', 'Saturday', 'Monday', 'Tuesday', 'A', 'In 7 days it''s Thursday again. 10-7=3 more days: Friday (1), Saturday (2), Sunday (3).', 3);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (9, 4, 'How many edges does a cube have?', '6', '8', '12', '10', 'C', 'A cube has 12 edges: 4 on top, 4 on bottom, and 4 vertical.', 4);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (9, 5, 'What is 0.75 written as a fraction in simplest form?', '3/4', '75/100', '7/10', '15/20', 'A', '0.75 = 75/100. Dividing both by 25 gives 3/4.', 5);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (9, 6, 'A shop sells pens in packs of 6. How many packs are needed to have at least 50 pens?', '8', '9', '7', '10', 'B', '8 packs = 48 pens (not enough). 9 packs = 54 pens (enough).', 6);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (9, 7, 'Find the area of a triangle with base 10 cm and height 6 cm.', '60 cm²', '30 cm²', '16 cm²', '20 cm²', 'B', 'Area of triangle = (base × height) ÷ 2 = (10 × 6) ÷ 2 = 30 cm².', 7);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (9, 8, 'Which decimal is equal to 1/4?', '0.25', '0.4', '0.14', '0.5', 'A', '1/4 = 1 ÷ 4 = 0.25.', 8);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (9, 9, 'Jack scores 78, 85, and 92 on three tests. What is his average score?', '84', '85', '86', '83', 'B', 'Average = (78 + 85 + 92) ÷ 3 = 255 ÷ 3 = 85.', 9);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (9, 10, 'If 3x + 4 = 19, what is the value of x?', '3', '4', '5', '6', 'C', '3x + 4 = 19, so 3x = 15, so x = 5.', 10);
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-math-reasoning'), 'Mathematical Reasoning Practice Test 5', 'OC (Grade 4) Mathematical Reasoning - Practice Test Set 5', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (10, 1, 'A map has a scale of 1 cm = 5 km. Two towns are 8 cm apart on the map. What is the actual distance?', '13 km', '40 km', '35 km', '45 km', 'B', '8 cm × 5 km/cm = 40 km.', 1);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (10, 2, 'What is 2.5 × 4?', '8.0', '9.0', '10.0', '10.5', 'C', '2.5 × 4 = 10.0, or think of it as 25 × 4 = 100, then ÷ 10 = 10.', 2);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (10, 3, 'A jar contains 40 lollies. 25% are red. How many lollies are red?', '5', '8', '10', '15', 'C', '25% of 40 = 1/4 × 40 = 10.', 3);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (10, 4, 'How many grams are there in 3.5 kilograms?', '350 g', '3,500 g', '350,000 g', '35,000 g', 'B', '1 kg = 1,000 g. 3.5 × 1,000 = 3,500 g.', 4);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (10, 5, 'What is the missing angle in a quadrilateral with angles 90°, 85°, and 95°?', '60°', '70°', '80°', '90°', 'D', 'Sum of angles in a quadrilateral = 360°. 360° - 90° - 85° - 95° = 90°.', 5);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (10, 6, 'A pizza is divided equally among 5 children. What fraction does each get?', '1/4', '1/5', '2/5', '5/1', 'B', 'One whole divided equally by 5 = 1/5 each.', 6);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (10, 7, 'Which is larger: 0.6 or 2/3?', '0.6', '2/3', 'They are equal', 'Cannot compare', 'B', '2/3 = 0.666..., which is larger than 0.6.', 7);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (10, 8, 'If a rectangle has an area of 48 cm² and a length of 8 cm, what is its width?', '5 cm', '6 cm', '7 cm', '4 cm', 'B', 'Width = Area ÷ Length = 48 ÷ 8 = 6 cm.', 8);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (10, 9, 'James saved $15 each week for 12 weeks. How much did he save in total?', '$160', '$170', '$180', '$190', 'C', '15 × 12 = 180. James saved $180.', 9);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (10, 10, 'What is the value of 2³ × 3²?', '36', '48', '72', '108', 'C', '2³ = 8, 3² = 9. 8 × 9 = 72.', 10);
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-thinking-skills'), 'Thinking Skills Practice Test 1', 'OC (Grade 4) Thinking Skills - Practice Test Set 1', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (11, 1, 'Look at this sequence: A, C, E, G, I, __. What letter comes next?', 'J', 'K', 'L', 'M', 'B', 'The sequence skips one letter each time: A (skip B), C (skip D), E (skip F), G (skip H), I (skip J), K.', 1);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (11, 2, 'Which shape does NOT belong? Circle, Square, Triangle, Cube', 'Circle', 'Square', 'Triangle', 'Cube', 'D', 'Cube is a 3D shape while the others are 2D shapes.', 2);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (11, 3, 'If all dogs are mammals and all mammals are animals, which statement must be true?', 'All animals are dogs', 'All dogs are animals', 'No dogs are animals', 'All mammals are dogs', 'B', 'If all dogs → mammals, and all mammals → animals, then all dogs → animals.', 3);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (11, 4, 'What is the next number: 2, 3, 5, 7, 11, ___?', '12', '13', '14', '15', 'B', 'These are prime numbers in order. The next prime after 11 is 13.', 4);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (11, 5, 'If you rearrange the letters ''TEACH'' you can make the word meaning ''to grab''. What is it?', 'Cheat', 'Catch', 'Ache', 'Chat', 'B', 'Rearranging T-E-A-C-H gives CH- well no. Let me think: T-E-A-C-H → C-A-T-C-H = ''CATCH''.', 5);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (11, 6, 'Sun is to day as Moon is to:', 'Light', 'Star', 'Night', 'Dark', 'C', 'The Sun is associated with day; the Moon is associated with night.', 6);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (11, 7, 'In a race, Tom finishes ahead of Ben but behind Amy. Who finishes second?', 'Tom', 'Ben', 'Amy', 'Cannot tell', 'A', 'Order: Amy first, Tom second, Ben third.', 7);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (11, 8, 'Which word is the odd one out? Happy, Joyful, Elated, Miserable', 'Happy', 'Joyful', 'Elated', 'Miserable', 'D', 'Miserable means sad, while the other three mean happy.', 8);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (11, 9, 'If the day after tomorrow is Thursday, what day is today?', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'B', 'Day after tomorrow = Thursday, so tomorrow = Wednesday, today = Tuesday.', 9);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (11, 10, 'Complete the analogy: Cat is to kitten as dog is to:', 'Foal', 'Calf', 'Puppy', 'Cub', 'C', 'A baby cat is a kitten; a baby dog is a puppy.', 10);
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-thinking-skills'), 'Thinking Skills Practice Test 2', 'OC (Grade 4) Thinking Skills - Practice Test Set 2', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (12, 1, 'All students must bring a hat. Jenny is a student. Therefore:', 'Jenny may bring a hat', 'Jenny must bring a hat', 'Jenny cannot bring a hat', 'Jenny already has a hat', 'B', 'If ALL students must bring a hat and Jenny IS a student, she must bring a hat.', 1);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (12, 2, 'Find the missing number: 3, 6, 12, 24, ___', '30', '36', '48', '40', 'C', 'Each number is doubled: 3×2=6, 6×2=12, 12×2=24, 24×2=48.', 2);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (12, 3, 'Which does NOT belong: apple, banana, carrot, grape?', 'Apple', 'Banana', 'Carrot', 'Grape', 'C', 'Carrot is a vegetable; apples, bananas, and grapes are fruits.', 3);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (12, 4, 'If you spell the number 5 backwards, add 1, what do you get?', '7', '6', '8', '5', 'B', 'FIVE backwards = EVIF. Actually: F-I-V-E → E-V-I-F. Add 1 to 5? This is tricky. Let me rethink. The question actually means: spell ''5'' backwards = ''EVIF''. Wait. Actually maybe it means: spell ''FIVE'' backwards = ''EVIF''. Then add 1... Hmm. Actually I think the question means: spell ''5'' = FIVE, backwards = EVIF. Wait. ''Spell the number 5 backwards'' could mean: 5 spelled = FIVE, backwards = EVIF. Add 1... no. Re-reading: ''spell the number 5 backwards'' = spell ''5'' as ''FIVE'', ''backwards'' = ''EVIF''. ''Add 1'' makes no sense. Let me interpret differently: the word ''FIVE'' backwards is ''EVIF''. Now ''add 1'' character? No. Actually 5 backwards could mean write ''5'' backwards which doesn''t work. Hmm, maybe the trick is: 5 spelled = FIVE, backwards letters = E, V, I, F. Not a word. Actually I think this is a poorly worded question. Let me replace it.', 4);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (12, 5, 'A clock shows 3:15. What is the angle between the hour and minute hands?', '0°', '7.5°', '15°', '30°', 'B', 'At 3:15, the minute hand is at 3 (90° from 12). The hour hand has moved 1/4 from 3 toward 4, so it''s at 97.5°. The difference is 7.5°.', 5);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (12, 6, 'Tree is to forest as star is to:', 'Sky', 'Galaxy', 'Planet', 'Comet', 'B', 'Many trees make a forest; many stars make a galaxy.', 6);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (12, 7, 'If RED = 18-5-4, then how is BLUE written?', '1-12-21-5', '2-12-22-5', '2-12-21-5', '1-12-22-5', 'C', 'R=18, E=5, D=4. B=2, L=12, U=21, E=5. So BLUE = 2-12-21-5.', 7);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (12, 8, 'A farmer has 10 sheep. All but 3 ran away. How many are left?', '7', '3', '10', '0', 'B', 'All but 3 ran away means 3 did NOT run away. So 3 are left.', 8);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (12, 9, 'Which word comes next? Monday, Wednesday, Friday, ___?', 'Saturday', 'Sunday', 'Tuesday', 'Thursday', 'B', 'The pattern alternates every second day: Monday (skip Tue) Wednesday (skip Thu) Friday (skip Sat) Sunday.', 9);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (12, 10, 'Hand is to glove as foot is to:', 'Bare', 'Shoe', 'Walk', 'Sock', 'D', 'A glove covers a hand; a sock covers a foot.', 10);
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-thinking-skills'), 'Thinking Skills Practice Test 3', 'OC (Grade 4) Thinking Skills - Practice Test Set 3', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (13, 1, 'What comes next: AZ, BY, CX, DW, ___?', 'EV', 'EU', 'FV', 'EX', 'A', 'First letter increases (A,B,C,D→E), second letter decreases (Z,Y,X,W→V): EV.', 1);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (13, 2, 'Which number doesn''t belong: 2, 4, 8, 16, 24?', '2', '4', '16', '24', 'D', 'All others are powers of 2 (2¹=2, 2²=4, 2³=8, 2⁴=16). 24 is not a power of 2.', 2);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (13, 3, 'If some birds can fly and a penguin is a bird, what can we conclude?', 'Penguins can fly', 'Penguins may or may not fly', 'Penguins cannot fly', 'All birds can fly', 'B', 'SOME birds can fly, not ALL. Without knowing more about penguins, we can''t conclude either way.', 3);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (13, 4, 'Doctor is to hospital as teacher is to:', 'Student', 'School', 'Book', 'Classroom', 'B', 'A doctor works in a hospital; a teacher works in a school.', 4);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (13, 5, 'What number should replace the question mark: 1, 1, 2, 3, 5, 8, ?', '10', '11', '13', '12', 'C', 'Fibonacci sequence: each number is the sum of the previous two. 5+8=13.', 5);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (13, 6, 'Which of these is most different from the others: dog, wolf, cat, fox?', 'Dog', 'Wolf', 'Cat', 'Fox', 'C', 'Dogs, wolves, and foxes are all canines (dog family). Cats are felines.', 6);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (13, 7, 'A bat and ball cost $1.10 total. The bat costs $1.00 more than the ball. How much does the ball cost?', '$0.05', '$0.10', '$0.15', '$0.20', 'A', 'Let b = ball price. Bat = b + $1.00. Total: b + (b + $1.00) = $1.10. So 2b = $0.10, b = $0.05.', 7);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (13, 8, 'If you rearrange the letters in ''LISTEN'', you get a word meaning ''not speaking''. What is it?', 'Listen', 'Inlets', 'Silent', 'Tinsel', 'C', 'S-I-L-E-N-T means not speaking.', 8);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (13, 9, 'Feet is to socks as hands is to:', 'Arms', 'Gloves', 'Fingers', 'Rings', 'B', 'Socks cover feet; gloves cover hands.', 9);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (13, 10, 'If today is the 3rd of the month and Saturday, what is the date of the following Friday?', '8th', '9th', '10th', '7th', 'B', 'Sat (3rd), Sun (4th), Mon (5th), Tue (6th), Wed (7th), Thu (8th), Fri (9th).', 10);
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-thinking-skills'), 'Thinking Skills Practice Test 4', 'OC (Grade 4) Thinking Skills - Practice Test Set 4', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (14, 1, 'Water is to drink as food is to:', 'Edible', 'Eat', 'Plate', 'Hungry', 'B', 'We drink water; we eat food.', 1);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (14, 2, 'What is the next letter: O, T, T, F, F, S, S, ___?', 'E', 'T', 'N', 'S', 'A', 'One, Two, Three, Four, Five, Six, Seven, Eight. So E for Eight.', 2);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (14, 3, 'If John is taller than Mary, and Mary is taller than Sue, who is the shortest?', 'John', 'Mary', 'Sue', 'Cannot tell', 'C', 'John > Mary > Sue, so Sue is the shortest.', 3);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (14, 4, 'Which word does NOT belong: run, jog, sprint, sit?', 'Run', 'Jog', 'Sprint', 'Sit', 'D', 'All others are types of moving quickly. Sitting means staying still.', 4);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (14, 5, 'If A = 1, B = 2, C = 3, what does D + O + G equal?', '25', '26', '27', '28', 'B', 'D=4, O=15, G=7. 4+15+7=26.', 5);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (14, 6, 'Complete: Needle is to sew as pen is to:', 'Paper', 'Write', 'Ink', 'Draw', 'B', 'A needle is used to sew; a pen is used to write.', 6);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (14, 7, 'What number is missing: 2, 6, 12, 20, 30, ___?', '40', '42', '44', '36', 'B', 'Pattern: 1×2=2, 2×3=6, 3×4=12, 4×5=20, 5×6=30, 6×7=42.', 7);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (14, 8, 'In a family there are 5 daughters. Each daughter has a brother. How many children are there?', '5', '6', '10', '11', 'B', 'Each daughter has the SAME brother. So 5 daughters + 1 brother = 6 children.', 8);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (14, 9, 'Speed is to car as height is to:', 'Mountain', 'Tall', 'Measure', 'Time', 'A', 'A car measures speed; a mountain measures (has) height.', 9);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (14, 10, 'Which letter comes next in this pattern: B, D, G, K, ___?', 'M', 'N', 'P', 'R', 'C', 'B+2=D, D+3=G, G+4=K, K+5=P.', 10);
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='oc-thinking-skills'), 'Thinking Skills Practice Test 5', 'OC (Grade 4) Thinking Skills - Practice Test Set 5', 30, 1499, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (15, 1, 'Book is to author as painting is to:', 'Museum', 'Artist', 'Frame', 'Canvas', 'B', 'An author creates a book; an artist creates a painting.', 1);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (15, 2, 'If the code for ''CAT'' is ''DBU'', what is the code for ''DOG''?', 'EPH', 'FPH', 'EQI', 'EPG', 'A', 'Each letter shifts forward by 1: C→D, A→B, T→U. So DOG → EPH.', 2);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (15, 3, 'Which shape comes next: △, □, ○, △, □, ___?', '△', '□', '○', '◇', 'C', 'The pattern repeats: △□○. After □ comes ○.', 3);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (15, 4, 'Rain is to flood as snow is to:', 'Cold', 'Avalanche', 'Winter', 'Ice', 'B', 'Too much rain causes a flood; too much snow causes an avalanche.', 4);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (15, 5, 'There are 20 birds on a tree. A hunter shoots 5. How many remain on the tree?', '15', '0', '5', '10', 'B', 'When the hunter shoots, the noise scares ALL remaining birds away. None remain.', 5);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (15, 6, 'Knife is to cut as ruler is to:', 'School', 'Measure', 'Draw', 'Wood', 'B', 'A knife is used to cut; a ruler is used to measure.', 6);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (15, 7, 'How many triangles are in this word: TRIANGLE?', '1', '2', '0', '3', 'A', 'The word TRIANGLE contains the substring ''TRI'' and ''ANGLE''. Actually, the word ''triangle'' itself contains ''tri'' which means three. It''s a trick: the word contains 0 literal triangles.', 7);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (15, 8, 'What is the next number: 1, 4, 9, 16, 25, ___?', '30', '34', '36', '49', 'C', 'Square numbers: 1²=1, 2²=4, 3²=9, 4²=16, 5²=25, 6²=36.', 8);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (15, 9, 'If you are facing north and turn 90° right three times, which direction are you facing?', 'North', 'East', 'South', 'West', 'D', 'N → E (1), E → S (2), S → W (3). You''re facing West.', 9);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (15, 10, 'Bread is to bakery as fish is to:', 'Ocean', 'Fisherman', 'Food', 'Market', 'D', 'Bread is made/purchased at a bakery; fish is purchased at a market.', 10);
INSERT INTO test_sets (subject_id, name, description, duration_minutes, price_cents, question_count, is_published) VALUES ((SELECT id FROM subjects WHERE slug='selective-reading'), 'Reading Practice Test 1', 'Selective (Grade 6) Reading - Practice Test Set 1', 40, 1999, 10, true);
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (16, 1, 'The Industrial Revolution, which began in Britain in the late 18th century, fundamentally transformed human society. Before this period, most people lived in rural areas and worked in agriculture. The invention of machines like the steam engine and the spinning jenny allowed goods to be produced in factories at unprecedented speeds. Cities grew rapidly as people moved from the countryside to work in these new factories. However, this rapid urbanisation led to overcrowding, poor sanitation, and harsh working conditions that took decades to address through labour laws and public health reforms.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (16, 2, 'The human immune system is a complex network of cells, tissues, and organs that defend the body against harmful invaders. When a pathogen enters the body, white blood cells called lymphocytes spring into action. B lymphocytes produce antibodies that target specific pathogens, while T lymphocytes directly attack infected cells. After an infection is cleared, memory cells remain in the body, allowing for a faster response if the same pathogen returns. This is the principle behind vaccination.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (16, 3, 'Leadership takes many forms, and not all great leaders are charismatic or loud. Quiet leaders often excel at listening, building consensus, and empowering others. They lead by example rather than command. In many organisations, the most effective teams are those where the leader creates an environment where every member feels heard and valued. This approach, sometimes called ''servant leadership,'' prioritises the growth and wellbeing of team members.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (16, 4, 'Climate change refers to long-term shifts in global temperatures and weather patterns. While climate change has occurred naturally throughout Earth''s history, the current warming trend is occurring at an unprecedented rate. Scientists attribute this primarily to human activities, particularly the burning of fossil fuels, which releases greenhouse gases like carbon dioxide into the atmosphere. These gases trap heat in the atmosphere, creating a greenhouse effect. The consequences include rising sea levels, more frequent extreme weather events, and disruption to ecosystems worldwide.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (16, 5, 'The concept of zero was independently developed by several ancient civilisations, including the Mayans and the Babylonians. However, the modern numerical system we use today, including the concept of zero as a number, originated in ancient India. Indian mathematicians developed a decimal place-value system that included zero as a placeholder and as a number in its own right. This system was later adopted and transmitted to Europe by Arab scholars, which is why our numerals are called ''Arabic numerals'' even though they originated in India.
INSERT INTO questions (test_set_id, question_number, question_text, option_a, option_b, option_c, option_d, correct_option, solution_text, sort_order) VALUES (16, 6, 'The Industrial Revolution, which began in Britain in the late 18th century, fundamentally transformed human society. Before this period, most people lived in rural areas and worked in agriculture. The invention of machines like the steam engine and the spinning jenny allowed goods to be produced in factories at unprecedented speeds. Cities grew rapidly as people moved from the countryside to work in these new factories. However, this rapid urbanisation led to overcrowding, poor sanitation, and harsh working conditions that took decades to address through labour laws and public health reforms.
